import React from 'react';

/**
 * Sidebar component for navigation
 */
const Sidebar = () => {
  return (
    <div className="bg-gray-900 w-64 h-full fixed left-0 top-0 p-4">
      <h2 className="text-xl font-bold mb-8">Sarang-Pulse</h2>
      <ul>
        <li className="mb-4">
          <a href="#" className="text-gray-300 hover:text-white">Dashboard</a>
        </li>
        <li className="mb-4">
          <a href="#" className="text-gray-300 hover:text-white">Tasks</a>
        </li>
        <li className="mb-4">
          <a href="#" className="text-gray-300 hover:text-white">Employees</a>
        </li>
        <li className="mb-4">
          <a href="#" className="text-gray-300 hover:text-white">Reports</a>
        </li>
      </ul>
    </div>
  );
};

/**
 * Navbar component for top navigation
 */
const Navbar = () => {
  return (
    <div className="bg-gray-800 p-4 ml-64">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-semibold">Unified Operations Dashboard</h1>
        <div className="flex items-center">
          <span className="mr-4">Welcome, User</span>
          <button className="bg-red-600 px-4 py-2 rounded">Logout</button>
        </div>
      </div>
    </div>
  );
};

/**
 * DashboardLayout component that includes Sidebar and Navbar
 * @param {Object} props - Component props
 * @param {React.ReactNode} props.children - Child components to render
 */
const DashboardLayout = ({ children }) => {
  return (
    <div className="min-h-screen bg-gray-900 text-white">
      <Sidebar />
      <div className="ml-64">
        <Navbar />
        <main className="p-6">
          {children}
        </main>
      </div>
    </div>
  );
};

export default DashboardLayout;
